package Day1_Assignment;

public class ASCII_value {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char alpha='A';
		int value=alpha;
		System.out.println("ASCII VALUE of A =" +value);
		
		
		char alpha1='a';
		int value1=alpha1;
		System.out.println("ASCII VALUE of a =" +value1);
		
		char alpha2='0';
		int value2=alpha2;
		System.out.println("ASCII VALUE of 0 =" +value2);
		
		char alpha3='@';
		int value3=alpha3;
		System.out.println("ASCII VALUE of @ =" +value3);
		
	



	}

}
